const WebSocket = require('ws');

const server = new WebSocket.Server({ port: 8080 });

const players = {};

server.on('connection', (ws) => {
    const playerId = generatePlayerId();
    players[playerId] = { ws, units: [], resources: 100 };

    ws.on('message', (message) => {
        const command = JSON.parse(message);
        processCommand(playerId, command);
    });

    ws.on('close', () => {
        delete players[playerId];
    });
});

function processCommand(playerId, command) {
    switch (command.type) {
        case 'build':
            buildUnit(playerId, command.unitType);
            break;
        case 'attack':
            attackUnit(playerId, command.targetId);
            break;
        case 'move':
            moveUnit(playerId, command.unitId, command.position);
            break;
        default:
            console.error('Unknown command type:', command.type);
    }
}

function buildUnit(playerId, unitType) {
    const player = players[playerId];
    if (player.resources >= getUnitCost(unitType)) {
        player.units.push({ id: generateUnitId(), type: unitType });
        player.resources -= getUnitCost(unitType);
        notifyPlayers();
    }
}

function attackUnit(playerId, targetId) {
    const player = players[playerId];
    const targetPlayer = findPlayerByUnitId(targetId);
    if (targetPlayer) {
        // Implement attack logic
        notifyPlayers();
    }
}

function moveUnit(playerId, unitId, position) {
    const player = players[playerId];
    const unit = player.units.find(u => u.id === unitId);
    if (unit) {
        unit.position = position;
        notifyPlayers();
    }
}

function notifyPlayers() {
    Object.values(players).forEach(player => {
        player.ws.send(JSON.stringify({ type: 'update', players: getGameState() }));
    });
}

function getGameState() {
    return Object.entries(players).map(([id, player]) => ({
        id,
        units: player.units,
        resources: player.resources,
    }));
}

function generatePlayerId() {
    return 'player-' + Math.random().toString(36).substr(2, 9);
}

function generateUnitId() {
    return 'unit-' + Math.random().toString(36).substr(2, 9);
}

function getUnitCost(unitType) {
    const costs = { soldier: 10, tank: 30 };
    return costs[unitType] || 0;
}

function findPlayerByUnitId(unitId) {
    return Object.values(players).find(player => player.units.some(unit => unit.id === unitId));
}